-- ============================================================
-- Seed: business_lines + proveedores + products + admin user
-- Ejecutar DESPUÉS de: alembic upgrade head
-- Uso: psql $DATABASE_URL -f scripts/seed_catalog.sql
-- ============================================================

BEGIN;

-- Lineas de negocio
TRUNCATE business_lines RESTART IDENTITY CASCADE;

-- Proveedores
TRUNCATE proveedores RESTART IDENTITY CASCADE;

-- Catálogo de productos
TRUNCATE products RESTART IDENTITY CASCADE;

-- Resetear secuencias
SELECT setval('business_lines_id_seq', (SELECT MAX(id) FROM business_lines));
SELECT setval('proveedores_id_seq',    (SELECT MAX(id) FROM proveedores));
SELECT setval('products_id_seq',       (SELECT MAX(id) FROM products));

COMMIT;
